// データベースを開く（バージョン1）
const request = indexedDB.open('myApp', 1);

// スキーマ作成（バージョンアップ時に実行）
request.onupgradeneeded = (event) => {
  const db = event.target.result;
  const store = db.createObjectStore('users', { keyPath: 'id', autoIncrement: true });
  store.createIndex('email', 'email', { unique: true });
  store.createIndex('name', 'name', { unique: false });
};

request.onsuccess = (event) => {
  const db = event.target.result;

  // データ追加
  const tx = db.transaction('users', 'readwrite');
  tx.objectStore('users').add({ name: '太郎', email: 'taro@example.com' });

  // データ取得
  const getTx = db.transaction('users', 'readonly');
  const getReq = getTx.objectStore('users').get(1);
  getReq.onsuccess = () => console.log(getReq.result);

  // インデックス検索
  const idx = getTx.objectStore('users').index('email');
  idx.get('taro@example.com').onsuccess = (e) => console.log(e.target.result);

  // 全件取得
  getTx.objectStore('users').getAll().onsuccess = (e) => console.log(e.target.result);
};

